import { useState, useEffect } from "react";
import KPICards from "./components/KPICards";
import DailyChart from "./components/DailyChart";
import MediaTable from "./components/MediaTable";
import Sidebar from "./components/Sidebar";
import Header from "./components/Header";

const API = "http://localhost:3001";

export default function App() {
  const [daily, setDaily] = useState(null);
  const [total, setTotal] = useState(null);
  const [media, setMedia] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [dailyRes, totalRes, mediaRes] = await Promise.all([
          fetch(`${API}/insights/daily`),
          fetch(`${API}/insights/total`),
          fetch(`${API}/media`),
        ]);

        const [dailyData, totalData, mediaData] = await Promise.all([
          dailyRes.json(),
          totalRes.json(),
          mediaRes.json(),
        ]);

        setDaily(dailyData);
        setTotal(totalData);
        setMedia(mediaData);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchAll();
  }, []);

  // ==========================
  // KPIs
  // ==========================
  const formattedTotal = {
    profile_views:
      total?.profile_views?.data?.[0]?.total_value?.value ?? 0,

    followers:
      total?.followers?.followers_count ?? 0,
  };

  // ==========================
  // 📈 GERAR 30 DIAS COMPLETOS
  // ==========================
  const generateLast30Days = () => {
    const days = [];
    const today = new Date();

    for (let i = 29; i >= 0; i--) {
      const d = new Date();
      d.setDate(today.getDate() - i);

      const dateStr = d.toISOString().split("T")[0];

      const apiValue =
        daily?.data?.[0]?.values?.find(v =>
          v.end_time.startsWith(dateStr)
        )?.value ?? 0;

      days.push({
        date: dateStr,
        reach: apiValue,
      });
    }

    return days;
  };

  const dailyFormatted = generateLast30Days();

  const mediaFormatted = media?.data || [];

  return (
    <div className="flex min-h-screen bg-[#0a0a0f] text-white">
      <Sidebar />

      <div className="flex-1 flex flex-col">
        <Header />

        <main className="p-8 space-y-8">
          {error && <div>{error}</div>}

          <KPICards data={formattedTotal} loading={loading} />
          <DailyChart data={dailyFormatted} loading={loading} />
          <MediaTable data={mediaFormatted} loading={loading} />
        </main>
      </div>
    </div>
  );
}
